#include <bits/stdc++.h>
using namespace std;

const int N=4e4+10;

struct Edge{
    int to,val;
    bool operator<(Edge x)const{
        return val<x.val;
    }
}p[N];

int n,k;
int sz[N],fa[N],bel[N],dis[N],cnt,sum[N];
vector<Edge> e[N];
bool b[N];
long long ans;

void dfs(int x,int lst){
    fa[x]=lst;
    sz[x]=1;
    for(Edge y:e[x])
        if(!b[y.to] && y.to!=lst){
            dfs(y.to,x);
            sz[x]+=sz[y.to];
        }
}

int Balance(int x,int S){
    for(Edge y:e[x])
        if(!b[y.to] && y.to!=fa[x] && sz[y.to]>S/2)
            return Balance(y.to,S);
    return x;
}

void dfs2(int x,int bl,int dist){
    dis[x]=dist;
    bel[x]=bl;
    if(dis[x]<=k)
        p[++cnt]={x,dis[x]};
    for(Edge y:e[x])
        if(!b[y.to] && y.to!=fa[x])
            dfs2(y.to,bl,dist+y.val);
}

void solve(int x){
    dfs(x,0);
    x=Balance(x,sz[x]);
    dfs(x,0);
    cnt=0;
    dis[x]=0,bel[x]=x,sum[x]=0;
    p[++cnt]={x,0};
    for(Edge y:e[x]){
        int v=y.to;
        if(!b[v]){
            sum[v]=0;
            dfs2(v,v,y.val);
        }
    }
    sum[0]=0;
    sort(p+1,p+cnt+1);
    for(int i=cnt,j=1;i;i--){
        while(j<=cnt && p[j].val+p[i].val<=k){
            sum[0]++,sum[bel[p[j].to]]++;
            j++;
        }
        ans+=sum[0]-sum[bel[p[i].to]];
    }
    b[x]=1;
    for(Edge y:e[x])
        if(!b[y.to])
            solve(y.to);
}

int main(){
    scanf("%d",&n);
    for(int i=1,u,v,w;i<n;i++){
        scanf("%d%d%d",&u,&v,&w);
        e[u].push_back({v,w});
        e[v].push_back({u,w});
    }
    scanf("%d",&k);
    solve(1);
    printf("%lld",ans/2);
    return 0;
}
